fn run() {
    input! {
        b: usize,
        g: usize,
        n: usize,
    }
    let mut ans = 0;
    for i in 0..=n {
        let x = i;
        let y = n - i;
        if x <= b && y <= g {
            ans += 1;
        }
    }
    println!("{}", ans);
}

fn main() {
    run();
}
